#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>

// Inline timer.h definitions
#include <unistd.h>
#include <stdint.h>
#include <stdlib.h>

__inline__ uint64_t rdtsc() 
{
     uint32_t lo, hi;
     __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
     return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#include <sys/time.h>

struct timeval starttime;
struct timeval endtime;

#define startTime() \
{ \
  gettimeofday(&starttime, 0); \
}
#define stopTime(valusecs) \
{ \
  gettimeofday(&endtime, 0); \
  valusecs = (endtime.tv_sec-starttime.tv_sec)*1000000+endtime.tv_usec-starttime.tv_usec; \
}

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

// CUDA kernel for the pathfinding computation
__global__ void pathfinder_kernel(int* dst, int* src, int* wall_row, int cols) {
    int n = threadIdx.x + blockIdx.x * blockDim.x;

    if (n < cols) {
        int min = src[n];
        if (0 < n)
            min = min < src[n-1] ? min : src[n-1];
        if (cols-1 > n)
            min = min < src[n+1] ? min : src[n+1];
        dst[n] = wall_row[n] + min;
    }
}

void
init(int argc, char** argv)
{
    if(3 == argc){
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
    }else{
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }
    data = new int[rows*cols];
    wall = new int*[rows];
    for(int n=0; rows > n; n++)
        wall[n]=data+cols*n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; cols > j; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int min;

    dst = result;
    src = new int[cols];

    // GPU memory allocation
    int *gpu_buf1, *gpu_buf2, *gpu_wall;
    cudaMalloc(&gpu_buf1, cols * sizeof(int));
    cudaMalloc(&gpu_buf2, cols * sizeof(int));
    cudaMalloc(&gpu_wall, rows * cols * sizeof(int));

    // Copy wall data to GPU
    cudaMemcpy(gpu_wall, data, rows * cols * sizeof(int), cudaMemcpyHostToDevice);

    // Initialize gpu_buf1 with wall[0]
    cudaMemcpy(gpu_buf1, wall[0], cols * sizeof(int), cudaMemcpyHostToDevice);

    pin_stats_reset();

    int block_size = 256;
    int num_blocks = (cols + block_size - 1) / block_size;

    // Track which buffer holds src vs dst (matches host pointer swap logic)
    int *gpu_src = gpu_buf1;
    int *gpu_dst = gpu_buf2;

    for (int t = 0; rows-1 > t; t++) {
        // Launch kernel - compute into gpu_dst from gpu_src and wall[t+1]
        pathfinder_kernel<<<num_blocks, block_size>>>(gpu_dst, gpu_src, gpu_wall + (t+1)*cols, cols);

        // Swap src and dst for next iteration (matches host pointer swap)
        int *temp_gpu = gpu_src;
        gpu_src = gpu_dst;
        gpu_dst = temp_gpu;
    }

    cudaDeviceSynchronize();

    // After loop, gpu_dst holds the final result
    // Copy to host result (dst points to result on host)
    cudaMemcpy(result, gpu_dst, cols * sizeof(int), cudaMemcpyDeviceToHost);

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    for (int i = 0; cols > i; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; cols > i; i++)

            printf("%d ",dst[i]) ;

    printf("\n") ;

#endif

    // Cleanup GPU memory
    cudaFree(gpu_buf1);
    cudaFree(gpu_buf2);
    cudaFree(gpu_wall);

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;
}
